#!/usr/bin/env bash
# tools/contract_test.sh — Phase 2: Python→Browser cross-contract test
#
# Proves that a replay generated by the Python pipeline is consumable by the
# browser-side TypeScript schema validator.
#
# Prerequisites:
#   - Python env with: gymnasium numpy pydantic  (no torch/sb3 needed)
#   - Node + npm ci already run (node_modules present)
#   - PYTHONPATH includes python/benchmark/src  (or use .venv)
#
# Usage (from repo root):
#   bash tools/contract_test.sh
#
# Optional env vars:
#   PYTHON        Python executable (default: python)
#   REPLAY_PATH   Override temp file path (default: /tmp/abyssal_contract_test.jsonl)
#
# Exit codes:
#   0 — both Python generation and TS validation passed
#   1 — either step failed

set -euo pipefail

REPO_ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"
PYTHON="${PYTHON:-python}"
REPLAY_PATH="${REPLAY_PATH:-/tmp/abyssal_contract_test.jsonl}"
SCRIPT="$REPO_ROOT/python/benchmark/scripts/generate_contract_test_replay.py"
VALIDATOR="$REPO_ROOT/tools/validate_replay.ts"

echo ""
echo "╔══════════════════════════════════════════════════════════════╗"
echo "║   abyssal-embodied-benchmark  ·  Cross-Contract Test        ║"
echo "╚══════════════════════════════════════════════════════════════╝"
echo ""

# ─── Step 1: Generate Python replay ──────────────────────────────────────────

echo "[ 1/2 ]  Generating replay with Python pipeline …"

cd "$REPO_ROOT"

if PYTHONPATH="python/benchmark/src${PYTHONPATH:+:$PYTHONPATH}" \
   "$PYTHON" "$SCRIPT" \
       --output "$REPLAY_PATH" \
       --seed 1 \
       --steps 20; then
    echo "         ✓ Python replay generated: $REPLAY_PATH"
else
    echo "         ✗ Python replay generation failed"
    exit 1
fi
echo ""

# ─── Step 2: Validate with TypeScript schema ──────────────────────────────────

echo "[ 2/2 ]  Validating replay with TypeScript schema …"

if npx --yes tsx "$VALIDATOR" "$REPLAY_PATH"; then
    echo "         ✓ TypeScript schema validation passed"
else
    echo "         ✗ TypeScript schema validation failed"
    exit 1
fi
echo ""

# ─── Done ─────────────────────────────────────────────────────────────────────

echo "══════════════════════════════════════════════════════════════"
echo "  Cross-contract test PASSED"
echo "  Python → JSONL → TypeScript Zod schema: OK"
echo "══════════════════════════════════════════════════════════════"
echo ""
